import{_ as a,o,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"ML Kit barcode scanning (Android)","description":"Notes on ML Kit barcode scanning (Android).","frontmatter":{"title":"ML Kit barcode scanning (Android)","description":"Notes on ML Kit barcode scanning (Android)."},"headers":[],"relativePath":"software-engineering/machine-learning/google-mlkit/mlkit-barcode-android.md","filePath":"software-engineering/machine-learning/google-mlkit/mlkit-barcode-android.md"}'),n={name:"software-engineering/machine-learning/google-mlkit/mlkit-barcode-android.md"};function i(d,e,l,s,c,g){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="ml-kit-barcode-scanning-android" tabindex="-1">ML Kit barcode scanning (Android) <a class="header-anchor" href="#ml-kit-barcode-scanning-android" aria-label="Permalink to &quot;ML Kit barcode scanning (Android)&quot;">​</a></h1><p>Recognize and decode barcodes (QR, EAN, PDF417, etc.) on-device with <strong>ML Kit</strong>.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://developers.google.com/ml-kit/vision/barcode-scanning/android" target="_blank" rel="noreferrer">Barcode scanning | Google for Developers</a></li></ul><h2 id="install-options" tabindex="-1">Install options <a class="header-anchor" href="#install-options" aria-label="Permalink to &quot;Install options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Gradle dependency</th><th>Trade-off</th></tr></thead><tbody><tr><td><strong>Bundled</strong></td><td><code>com.google.mlkit:barcode-scanning:17.3.0</code></td><td>+~2.4 MB, instant model</td></tr><tr><td><strong>Play Services</strong></td><td><code>com.google.android.gms:play-services-mlkit-barcode-scanning:18.3.1</code></td><td>+~200 KB, may download on first use</td></tr></tbody></table><p>Requires <code>minSdkVersion</code> <strong>23+</strong>. Add Google Maven to project <code>build.gradle</code>.</p><h2 id="basic-usage-pattern" tabindex="-1">Basic usage pattern <a class="header-anchor" href="#basic-usage-pattern" aria-label="Permalink to &quot;Basic usage pattern&quot;">​</a></h2><ol><li>Build <code>InputImage</code> from CameraX, <code>Bitmap</code>, or byte buffer</li><li>Create <code>BarcodeScanner</code> via <code>BarcodeScanning.getClient()</code></li><li>Call <code>process(image)</code> and handle <code>List&lt;Barcode&gt;</code> (format, raw bytes, corner points)</li></ol><p>For simple QR-only flows, Google’s <strong>Code Scanner</strong> API may be faster and permission-light.</p><h2 id="image-quality" tabindex="-1">Image quality <a class="header-anchor" href="#image-quality" aria-label="Permalink to &quot;Image quality&quot;">​</a></h2><ul><li>Smallest barcode unit should be <strong>≥ 2 pixels</strong> wide (2D: 2 px tall)</li><li>EAN-13 ideally <strong>≥ 190 px</strong> wide; dense PDF417 needs more resolution</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">Google MLKit</a></li><li><a href="./../../browsers/apis/browser-barcodedetect-api-using-image.html">Browser BarcodeDetect API</a></li></ul>',14)])])}const u=a(n,[["render",i]]);export{h as __pageData,u as default};
